namespace sv_0fc0cdd95c564d7e94fa754a58c44d90.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped (per-circuit) service that holds theme state and notifies
/// subscribers when it changes. Because it is scoped, each user's
/// circuit gets its own independent instance.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd"; // Bootstrap primary blue

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Raised whenever Theme or AccentColor changes.
    /// Interactive components subscribe to this to re-render.
    /// </summary>
    public event Action? OnChange;

    /// <summary>
    /// Apply multiple changes as a batch, raising OnChange only once.
    /// </summary>
    public void Update(ThemeMode theme, string accentColor)
    {
        bool changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) NotifyChanged();
    }

    private void NotifyChanged() => OnChange?.Invoke();
}

@* Interactive island that lives in the static layout header.
   It subscribes to ThemeService so it re-renders on every change. *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator" title="Current theme">
    @switch (ThemeService.Theme)
    {
        case ThemeMode.Light:
            <span>☀️ Light</span>
            break;
        case ThemeMode.Dark:
            <span>🌙 Dark</span>
            break;
        case ThemeMode.System:
            <span>💻 System</span>
            break;
    }
    <span class="accent-dot" style="background-color: @ThemeService.AccentColor;"
          title="Accent: @ThemeService.AccentColor"></span>
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@* Quick toggle that can be dropped into the sidebar or any interactive area. *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<div class="theme-toggle">
    <button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
            title="Toggle theme">
        @switch (ThemeService.Theme)
        {
            case ThemeMode.Light:
                <span>☀️</span>
                break;
            case ThemeMode.Dark:
                <span>🌙</span>
                break;
            case ThemeMode.System:
                <span>💻</span>
                break;
        }
    </button>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _ => ThemeMode.Light
        };
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@ThemeService.Theme"
                    @onchange="OnThemeSelected">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeService.AccentColor"
                       @onchange="OnAccentChanged" />
                <span class="text-muted">@ThemeService.AccentColor</span>
            </div>
        </div>

        <div class="alert alert-info mb-0">
            Changes are applied instantly to all components, including the
            header theme indicator and any themed content on other pages.
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnThemeSelected(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            ThemeService.Theme = mode;
        }
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? ThemeService.AccentColor;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

